// Sauvegarde des modifications
const storeFile = "file";
let enrichedVars = global.get("enrichedVars", storeFile) || {};
let formData = msg.payload || {};

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Données invalides.";
    return null;
}

// Vérification et renommage de "valeurCourante" si nécessaire
if (formData.instances && formData.instances.length > 1 && formData.instances.includes("*")) {
    let index = 0;
    let newInstanceName = `instance${index}`;
    while (formData.instances.includes(newInstanceName)) {
        index++;
        newInstanceName = `instance${index}`;
    }
    // Renommer "*" en "instanceX"
    let valeursCourantes = {};
    formData.proprietesByInstance.proprietes.forEach(prop => {
        if (prop.valeurs && prop.valeurs["*"]) {
            valeursCourantes[prop.nom] = prop.valeurs["*"];
        }
    });
    // Mettre à jour les instances
    let newInstances = formData.instances.map(instance => instance === "*" ? newInstanceName : instance);
    formData.instances = newInstances;
    // Mettre à jour les valeurs des propriétés
    formData.proprietesByInstance.proprietes.forEach(prop => {
        if (prop.valeurs && prop.valeurs["*"]) {
            prop.valeurs[newInstanceName] = prop.valeurs["*"];
            delete prop.valeurs["*"];
        }
    });
}

const varName = formData.nomVarG;
enrichedVars[varName] = formData;
global.set("enrichedVars", enrichedVars, storeFile);
msg.payload = enrichedVars[varName];
msg.info = `💾 Variable '${varName}' sauvegardée.`;
return msg;

// PrepareTemplate → Prépare les données pour le template Vue.js
let enrichedVars = global.get("enrichedVars", "file") || {};
let varName = flow.get("varSelected") || msg.payload || null;
let variable = varName ? enrichedVars[varName] : null;

if (!variable) {
    msg.info = "Variable non trouvée pour l'éditeur de propriétés.";
    msg.payload = null;
    return msg;
}

// Fonction utilitaire pour convertir en tableau
const toArray = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v === "string" && v.trim()) {
        return v.includes(",") ? v.split(",").map(x => x.trim()) : [v.trim()];
    }
    return ["*"];
};

// Fonction utilitaire pour désérialiser les valeurs
const deserializeValue = (value, type) => {
    if (value === undefined || value === null) {
        return defaultForType(type);
    }
    try {
        switch (type) {
            case "object":
                return typeof value === "object" ? value : JSON.parse(value);
            case "array":
                return Array.isArray(value) ? value : JSON.parse(value);
            case "boolean":
                return value === true || value === "true";
            case "int":
            case "number":
                return parseFloat(value) || 0;
            default:
                return value;
        }
    } catch (e) {
        console.warn(`Désérialisation échouée pour le type ${type}:`, e);
        return defaultForType(type);
    }
};

// Fonction utilitaire pour obtenir une valeur par défaut selon le type
const defaultForType = (type) => {
    switch (type) {
        case "boolean":
            return false;
        case "int":
        case "number":
            return 0;
        case "array":
            return [];
        case "object":
            return {};
        case "date":
            return new Date().toISOString().slice(0, 10);
        default:
            return "";
    }
};

// Instances → toujours un tableau
let instances = toArray(variable.instances || ["*"]);

// Propriétés → nettoyage et validation
let propArr = [];
if (variable.proprietesByInstance?.proprietes) {
    propArr = variable.proprietesByInstance.proprietes
        .filter(p => p && typeof p.nom === "string" && typeof p.type === "string")
        .map(p => ({
            nom: String(p.nom),
            abbr: p.abbr || "",
            type: String(p.type),
            defaultVal: p.defaultVal || (p.type === "object" ? {} : p.type === "array" ? [] : { "type": p.type, "default": defaultForType(p.type) }),
            valeurs: p.valeurs || {}
        }));
}

// Abréviations des propriétés
let abbrMap = {};
if (variable.proprietesByInstance?.abbrProprietes && typeof variable.proprietesByInstance.abbrProprietes === "object") {
    abbrMap = JSON.parse(JSON.stringify(variable.proprietesByInstance.abbrProprietes));
}

// Valeurs → désérialisation des objets/tableaux
let valeurs = {};
instances.forEach(inst => {
    valeurs[inst] = {};
    propArr.forEach(p => {
        const storedValue = p.valeurs[inst];
        valeurs[inst][p.nom] = deserializeValue(storedValue, p.type);
    });
});

// Payload pour le template
msg.payload = {
    nomVarG: variable.nomVarG || varName,
    abbrVarG: variable.abbrVarG || "",
    instances,
    proprietesByInstance: {
        proprietes: propArr,
        abbrProprietes: abbrMap,
        valeurs
    },
    descriptionVarG: variable.descriptionVarG || "",
    dateUpdateVarG: variable.dateUpdateVarG || new Date().toISOString()
};
msg.info = "✅ Données préparées pour le template.";
return msg;

// Variable globale pour stocker le schéma provisoire
let schemaProvisoire = {};

// Fonction pour ouvrir l'éditeur de schéma
function openSchemaEditor(prop) {
    // Sauvegarde du schéma actuel dans schemaProvisoire
    schemaProvisoire = JSON.parse(JSON.stringify(prop.defaultVal || {}));
    return schemaProvisoire;
}

// Fonction pour mettre à jour le schéma provisoire
function updateSchemaProvisoire(key, type, defaultValue) {
    schemaProvisoire[key] = { type, default: defaultValue };
    return schemaProvisoire;
}

// Fonction pour sauvegarder le schéma provisoire dans la propriété
function saveSchema(prop) {
    if (!schemaProvisoire) {
        console.error("Aucun schéma provisoire à sauvegarder.");
        return false;
    }
    prop.defaultVal = JSON.parse(JSON.stringify(schemaProvisoire));
    schemaProvisoire = {}; // Réinitialisation du schéma provisoire
    return true;
}

// Route les actions venant du tableau
// - met à jour flow.propSelected
// - envoie seulement la propriété et les instances nécessaires aux éditeurs

let action = msg.action;
let prop = msg.prop || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};
let instances = (variable.instances || []).filter(i => i !== '*'); // instances visibles (sans '*')

if (action) {
    // set selected property for continuity
    flow.set('propSelected', prop && prop.nomP ? prop.nomP : null);
}

if (action === 'base') {
    // Forward to base editor (for define). include originalName if editing existing
    let out = { topic: 'openEditor', editor: 'base', prop: prop, instances: instances, originalName: prop && prop._isNew ? null : (prop && prop.nomP ? prop.nomP : null) };
    return [out, null, null];
}
else if (action === 'valeurs') {
    // forward minimal payload to values editor
    let out = { topic: 'openEditor', editor: 'valeurs', prop: prop, instances: instances, originalName: prop && prop.nomP ? prop.nomP : null };
    return [null, out, null];
}
else if (action === 'delete') {
    // forward to delete handler
    let out = { topic: 'delete', prop: prop };
    return [null, null, out];
}
return null;

// Nœud deleteItem
if (msg.topic !== "deleteItem") {
    msg.error = "Mauvais nœud pour cette action.";
    return null;
}

let payload = msg.payload;
let enrichedVars = global.get("enrichedVars", "file") || {};
let varName = payload.nomVarG;

if (!varName || !enrichedVars[varName]) {
    msg.error = "Variable non trouvée.";
    return null;
}

// Supprimer une propriété
if (payload.type === "propriete") {
    let propIndex = enrichedVars[varName].proprietesByInstance.proprietes.findIndex(p => p.nom === payload.nom);
    if (propIndex !== -1) {
        enrichedVars[varName].proprietesByInstance.proprietes.splice(propIndex, 1);
        // Supprimer les valeurs associées à cette propriété
        enrichedVars[varName].instances.forEach(instance => {
            delete enrichedVars[varName].proprietesByInstance.valeurs[instance][payload.nom];
        });
    }
}
// Supprimer une instance
else if (payload.type === "instance") {
    let instanceIndex = enrichedVars[varName].instances.indexOf(payload.nom);
    if (instanceIndex !== -1) {
        enrichedVars[varName].instances.splice(instanceIndex, 1);
        // Supprimer les valeurs associées à cette instance
        delete enrichedVars[varName].proprietesByInstance.valeurs[payload.nom];
    }
}

// Sauvegarder les modifications
global.set("enrichedVars", enrichedVars, "file");

msg.payload = enrichedVars[varName];
msg.topic = "refreshData";
return msg;

// Nœud editBase
if (msg.topic !== "editBase") {
    msg.error = "Mauvais nœud pour cette action.";
    return null;
}

let payload = msg.payload;
let enrichedVars = global.get("enrichedVars", "file") || {};
let varName = payload.nomVarG;

if (!varName || !enrichedVars[varName]) {
    msg.error = "Variable non trouvée.";
    return null;
}

// Mettre à jour les propriétés de base
enrichedVars[varName].nomVarG = payload.nomVarG;
enrichedVars[varName].abbrVarG = payload.abbrVarG;
enrichedVars[varName].descriptionVarG = payload.descriptionVarG;
enrichedVars[varName].instances = payload.instances;

// Sauvegarder les modifications
global.set("enrichedVars", enrichedVars, "file");

msg.payload = enrichedVars[varName];
msg.topic = "refreshData";
return msg;

// Nœud editValues
if (msg.topic !== "editValues") {
    msg.error = "Mauvais nœud pour cette action.";
    return null;
}

let payload = msg.payload;
let enrichedVars = global.get("enrichedVars", "file") || {};
let varName = payload.nomVarG;

if (!varName || !enrichedVars[varName]) {
    msg.error = "Variable non trouvée.";
    return null;
}

// Mettre à jour les valeurs des propriétés
payload.proprietesByInstance.proprietes.forEach(prop => {
    payload.instances.forEach(instance => {
        if (payload.proprietesByInstance.valeurs[instance] && payload.proprietesByInstance.valeurs[instance][prop.nom] !== undefined) {
            enrichedVars[varName].proprietesByInstance.valeurs[instance][prop.nom] = payload.proprietesByInstance.valeurs[instance][prop.nom];
        }
    });
});

// Sauvegarder les modifications
global.set("enrichedVars", enrichedVars, "file");

msg.payload = enrichedVars[varName];
msg.topic = "refreshData";
return msg;

// Route les actions venant du tableau
// - met à jour flow.propSelected
// - envoie seulement la propriété et les instances nécessaires aux éditeurs

let action = msg.action;
let prop = msg.prop || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};
let instances = (variable.instances || []).filter(i => i !== '*'); // instances visibles (sans '*')

if (action) {
    // set selected property for continuity
    flow.set('propSelected', prop && prop.nomP ? prop.nomP : null);
}

if (action === 'base') {
    // Forward to base editor (for define). include originalName if editing existing
    let out = { topic: 'openEditor', editor: 'base', prop: prop, instances: instances, originalName: prop && prop._isNew ? null : (prop && prop.nomP ? prop.nomP : null) };
    return [out, null, null];
}
else if (action === 'valeurs') {
    // forward minimal payload to values editor
    let out = { topic: 'openEditor', editor: 'valeurs', prop: prop, instances: instances, originalName: prop && prop.nomP ? prop.nomP : null };
    return [null, out, null];
}
else if (action === 'delete') {
    // forward to delete handler
    let out = { topic: 'delete', prop: prop };
    return [null, null, out];
}
return null;

// Prépare l'affichage du tableau des propriétés
// Gère varSelected et propSelected pour la continuité de traitement

let varSelected = flow.get("varSelected") || null;
let enrichedVars = global.get("enrichedVars", "file") || {};
let variable = enrichedVars[varSelected] || {};

// Si aucune variable sélectionnée → pas de propriétés
if (!varSelected || !variable.proprietes) {
    msg.payload = { proprietes: [] };
    msg.info = "⚠️ Aucune variable sélectionnée.";
    return msg;
}

// Récupère propSelected pour affichage conditionnel des éditeurs
let propSelected = flow.get("propSelected") || null;

msg.payload = {
    proprietes: variable.proprietes,
    propSelected: propSelected
};
msg.info = `📋 Tableau propriétés de ${varSelected}`;
return msg;

// CHANGEMENT : gère schemaProvisoire si type=object/array

let prop = msg.payload || {};
flow.set("propSelected", prop);

// Vérifie si un schema provisoire existe pour cette propriété
let schemaProvisoire = flow.get("schemaProvisoire") || null;
if ((prop.typeP === "object" || prop.typeP === "array") && schemaProvisoire) {
    prop.schema = schemaProvisoire;
}

msg.payload = prop;
msg.info = `📝 Edition base pour ${prop.nomP}`;
return msg;

// Prépare l'éditeur de valeurs
// - Adapte selon le type et le schéma si object/array

let prop = msg.payload || {};
flow.set("propSelected", prop);

let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars", "file") || {};
let variable = enrichedVars[varSelected] || {};
let instances = variable.instances || ["*"];

let valeurs = prop.valeurs || {};
let valeursInstances = [];

// Cas object/array avec schéma → construire par sous-propriétés
if ((prop.typeP === "object" || prop.typeP === "array") && prop.schema) {
    try {
        let schema = typeof prop.schema === "string" ? JSON.parse(prop.schema) : prop.schema;
        instances.forEach(inst => {
            let val = valeurs[inst] || {};
            let sous = schema.map(ssp => {
                return {
                    nomSsP: ssp.nomSsP,
                    typeSsP: ssp.typeSsP,
                    valeur: val[ssp.nomSsP] || null
                };
            });
            valeursInstances.push({ instance: inst, sousProps: sous, type: prop.typeP });
        });
    } catch(e) {
        node.warn("Erreur parsing schema: " + e);
    }
}
else {
    // Cas simple (string, number, boolean)
    instances.forEach(inst => {
        valeursInstances.push({
            instance: inst,
            valeur: valeurs[inst] !== undefined ? valeurs[inst] : "",
            type: prop.typeP
        });
    });
}

msg.payload = {
    nomPropriete: prop.nomP,
    typePropriete: prop.typeP,
    valeursInstances: valeursInstances,
    schema: prop.schema || null
};
msg.info = `📝 Edition valeurs pour ${prop.nomP}`;
return msg;

// Sauvegarde la base + schéma (si défini)

let prop = msg.payload;
let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars","file") || {};
let variable = enrichedVars[varSelected] || {};

let proprietes = variable.proprietes || [];

let index = proprietes.findIndex(p => p.nomP === prop.nomP);
if (index >= 0) {
    proprietes[index] = prop;
} else {
    proprietes.push(prop);
}

variable.proprietes = proprietes;
enrichedVars[varSelected] = variable;
global.set("enrichedVars", enrichedVars, "file");

// Reset schemaProvisoire
flow.set("schemaProvisoire", null);

msg.topic = "refreshTableauProprietes";
msg.info = `✅ Propriété ${prop.nomP} sauvegardée.`;
return msg;

// Sauvegarde des valeurs
let formData = msg.payload;
let varSelected = flow.get("varSelected");
let propSelected = flow.get("propSelected");
let enrichedVars = global.get("enrichedVars","file") || {};

let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];
let index = proprietes.findIndex(p => p.nomP === propSelected.nomP);

if (index >= 0) {
    let valeurs = {};
    formData.valeursInstances.forEach(vi => {
        if (vi.sousProps) {
            // Reconstruction objet
            let obj = {};
            vi.sousProps.forEach(ssp => { obj[ssp.nomSsP] = ssp.valeur; });
            valeurs[vi.instance] = obj;
        } else {
            valeurs[vi.instance] = vi.valeur;
        }
    });
    proprietes[index].valeurs = valeurs;
    variable.proprietes = proprietes;
    enrichedVars[varSelected] = variable;
    global.set("enrichedVars", enrichedVars, "file");

    msg.topic = "refreshTableauProprietes";
    msg.info = `✅ Valeurs de ${propSelected.nomP} sauvegardées.`;
}
else {
    msg.info = "❌ Propriété non trouvée.";
}
return msg;

// Suppression propriété
let prop = msg.payload;
let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars","file") || {};
let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];

proprietes = proprietes.filter(p => p.nomP !== prop.nomP);
variable.proprietes = proprietes;
enrichedVars[varSelected] = variable;
global.set("enrichedVars", enrichedVars, "file");

msg.topic = "refreshTableauProprietes";
msg.info = `🗑️ Propriété ${prop.nomP} supprimée.`;
return msg;
